# cook your dish here
z=int(input())
for _ in range(z):
    n=int(input())
    s=input()
    t=''
    for i in range(0,len(s),2):

        if(s[i:i+2]=='00'):
            t+='A'
        elif(s[i:i+2]=='01'):
            t+='T'
        elif(s[i:i+2]=='10'):
            t+='C'
        elif(s[i:i+2]=='11'):
            t+='G'

    print(t)

